  function [PORT_BITS:0] get_priority_port();
    bit result = 0;
    for (int i = 0; i < NUM_PORTS; i++) begin : priority_loop
      $display("Port %d is %b", i, port_req[i] || port_req_queue[i]);
      if (port_req[i] || port_req_queue[i]) begin
        result = i;
        break;
      end
    end
    $display("Priority port identified as %b", result);
    return result;
  endfunction
